109	var lv, rv, fv, av: PVal;
110	    l, r, x, body_node: PExpr;
111	    new_env, closure_env: PEnv;
112	    a, b, res: integer;
113	begin
114	  eval_expr := nil;
115	  if e = nil then begin eval_error := true; exit end;
116	
