118	  begin eval_expr := mk_val_int(e^.ival); exit end;
119	
120	  if e^.kind = EK_BOOL then
121	  begin eval_expr := mk_val_bool(e^.ival); exit end;
122	
123	  if e^.kind = EK_VAR then
124	  begin
125	    { Check for print_int built-in }
126	    if names_equal(e^.noff, e^.nlen, print_int_noff, print_int_nlen) then
127	    begin
128	      { Return a special closure-like value; handled at application }
129	      eval_expr := mk_val_int(-1);
130	      eval_expr^.vk := VK_CLOSURE;
131	      eval_expr^.noff := print_int_noff;
132	      eval_expr^.nlen := print_int_nlen;
133	      eval_expr^.body := nil;
134	      exit
135	    end;
136	    eval_expr := env_lookup(env, e^.noff, e^.nlen);
137	    exit
138	  end;
139	
140	  if e^.kind = EK_BINOP then
141	  begin
142	    l := e^.left; r := e^.right;
143	    lv := eval_expr(l, env);
144	    rv := eval_expr(r, env);
145	    if eval_error then exit;
146	    a := lv^.ival; b := rv^.ival;
147	    res := 0;
148	    if e^.op = OP_ADD then res := a + b
149	    else if e^.op = OP_SUB then res := a - b
150	    else if e^.op = OP_MUL then res := a * b
151	    else if e^.op = OP_DIV then begin
152	      if b = 0 then begin eval_error := true; exit end;
153	      res := a div b
154	    end
155	    else if e^.op = OP_MOD then begin
156	      if b = 0 then begin eval_error := true; exit end;
157	      res := a mod b
158	    end
159	    else if e^.op = OP_EQ then begin if a = b then res := 1 else res := 0 end
160	    else if e^.op = OP_NEQ then begin if a <> b then res := 1 else res := 0 end
161	    else if e^.op = OP_LT then begin if a < b then res := 1 else res := 0 end
162	    else if e^.op = OP_GT then begin if a > b then res := 1 else res := 0 end
163	    else if e^.op = OP_LE then begin if a <= b then res := 1 else res := 0 end
164	    else if e^.op = OP_GE then begin if a >= b then res := 1 else res := 0 end
165	    else if e^.op = OP_AND then begin if (a <> 0) and (b <> 0) then res := 1 else res := 0 end
166	    else if e^.op = OP_OR then begin if (a <> 0) or (b <> 0) then res := 1 else res := 0 end;
167	    { comparison/logic ops return bool, arithmetic returns int }
168	    if (e^.op >= OP_EQ) and (e^.op <= OP_OR) then
169	      eval_expr := mk_val_bool(res)
170	    else
171	      eval_expr := mk_val_int(res);
172	    exit
173	  end;
174	
175	  if e^.kind = EK_UNARY then
176	  begin
177	    l := e^.left;
178	    lv := eval_expr(l, env);
179	    if eval_error then exit;
180	    if e^.op = OP_NOT then
181	    begin
182	      if lv^.ival = 0 then eval_expr := mk_val_bool(1)
183	      else eval_expr := mk_val_bool(0)
184	    end;
185	    exit
186	  end;
187	
188	  if e^.kind = EK_IF then
189	  begin
190	    l := e^.left;
191	    lv := eval_expr(l, env);
192	    if eval_error then exit;
193	    if lv^.ival <> 0 then
194	    begin r := e^.right; eval_expr := eval_expr(r, env) end
195	    else
196	    begin x := e^.extra; eval_expr := eval_expr(x, env) end;
197	    exit
198	  end;
199	
200	  if e^.kind = EK_LET then
201	  begin
202	    l := e^.left;
203	    if e^.ival = 1 then
204	    begin
205	      { let rec: create closure that can reference itself }
206	      lv := mk_val_closure(0, 0, nil, nil);
207	      new_env := env_extend(env, e^.noff, e^.nlen, lv);
208	      rv := eval_expr(l, new_env);
209	      if eval_error then exit;
210	      { Patch the placeholder with the real value }
211	      lv^.vk := rv^.vk;
212	      lv^.ival := rv^.ival;
213	      lv^.noff := rv^.noff;
214	      lv^.nlen := rv^.nlen;
215	      lv^.body := rv^.body;
216	      { For recursive closure, point env back to new_env }
217	      lv^.env := new_env
218	    end
219	    else
220	    begin
221	      lv := eval_expr(l, env);
222	      if eval_error then exit;
223	      new_env := env_extend(env, e^.noff, e^.nlen, lv)
224	    end;
225	    r := e^.right;
226	    eval_expr := eval_expr(r, new_env);
227	    exit
228	  end;
229	
230	  if e^.kind = EK_FUN then
231	  begin
232	    eval_expr := mk_val_closure(e^.noff, e^.nlen, e^.left, env);
233	    exit
234	  end;
235	
236	  if e^.kind = EK_APP then
237	  begin
238	    l := e^.left;
239	    fv := eval_expr(l, env);
240	    if eval_error then exit;
241	    r := e^.right;
242	    av := eval_expr(r, env);
243	    if eval_error then exit;
244	    if fv^.vk = VK_CLOSURE then
245	    begin
246	      if fv^.body = nil then
247	      begin
248	        { Built-in: print_int }
249	        if names_equal(fv^.noff, fv^.nlen, print_int_noff, print_int_nlen) then
250	        begin
251	          writeln(av^.ival);
252	          eval_expr := mk_val_unit;
253	          exit
254	        end;
255	        eval_error := true; exit
256	      end;
257	      body_node := fv^.body;
258	      closure_env := fv^.env;
259	      new_env := env_extend(closure_env, fv^.noff, fv^.nlen, av);
260	      eval_expr := eval_expr(body_node, new_env);
261	      exit
262	    end;
263	    eval_error := true;
264	    exit
265	  end;
266	
